import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import styles from './Header.module.css';
import logo from '../assets/images/logo.png';

const megaMenuData = {
  women: {
    'READY TO WEAR': [
      { name: 'OUTERWEAR', link: '/collection/women?category=outerwear' },
      { name: 'JACKETS', link: '/collection/women?category=jackets' },
      { name: 'TOPS & T-SHIRTS', link: '/collection/women?category=tops' },
      { name: 'SHIRTS & BLOUSES', link: '/collection/women?category=shirts' },
      { name: 'KNITWEAR', link: '/collection/women?category=knitwear' },
      { name: 'DRESSES', link: '/collection/women?category=dresses' },
      { name: 'SKIRTS', link: '/collection/women?category=skirts' },
      { name: 'PANTS', link: '/collection/women?category=pants' },
      { name: 'SIGNATURE LEATHER', link: '/collection/women?category=signature-leather' },
      { name: 'ESSENTIAL', link: '/collection/women?category=essential' },
      { name: 'ALL', link: '/collection/women' },
    ],
    BAG: [
      { name: 'SINGULAR BAG', link: '/collection/women?category=bags&sub=singular' },
      { name: '21 LEATHER BUCKET BAG', link: '/collection/women?category=bags&sub=bucket' },
      { name: 'ALL', link: '/collection/women?category=bags' },
    ],
    SHOES: [
      { name: 'ALL', link: '/collection/women?category=shoes' },
    ],
    ACCESSORIES: [
      { name: 'ALL', link: '/collection/women?category=accessories' },
    ],
    'PREVIOUS SEASON': [
      { name: 'ALL', link: '/collection/women?category=previous' },
    ],
  },
  men: {
    'READY TO WEAR': [
      { name: 'OUTERWEAR', link: '/collection/men?category=outerwear' },
      { name: 'JACKETS', link: '/collection/men?category=jackets' },
      { name: 'TOPS & T-SHIRTS', link: '/collection/men?category=tops' },
      { name: 'SHIRTS', link: '/collection/men?category=shirts' },
      { name: 'KNITWEAR', link: '/collection/men?category=knitwear' },
      { name: 'PANTS', link: '/collection/men?category=pants' },
      { name: 'SIGNATURE LEATHER', link: '/collection/men?category=signature-leather' },
      { name: 'ESSENTIAL', link: '/collection/men?category=essential' },
      { name: 'ALL', link: '/collection/men' },
    ],
    BAG: [
      { name: 'SINGULAR BAG', link: '/collection/men?category=bags&sub=singular' },
      { name: '21 LEATHER BUCKET BAG', link: '/collection/men?category=bags&sub=bucket' },
      { name: 'ALL', link: '/collection/men?category=bags' },
    ],
    SHOES: [
      { name: 'ALL', link: '/collection/men?category=shoes' },
    ],
    ACCESSORIES: [
      { name: 'ALL', link: '/collection/men?category=accessories' },
    ],
    'PREVIOUS SEASON': [
      { name: 'ALL', link: '/collection/men?category=previous' },
    ],
  },
};

function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [activeMega, setActiveMega] = useState(null);
  const headerRef = useRef(null);
  const location = useLocation();
  const { cartCount } = useCart();

  const navLeft = [
    { label: 'WOMEN', key: 'women' },
    { label: 'MEN', key: 'men' },
    { label: 'ABOUT', key: 'about' },
    { label: 'COLLECTIONS', key: 'collections' },
  ];
  const navRight = ['SEARCH', 'ACCOUNT'];

  const closeMega = useCallback(() => setActiveMega(null), []);

  // Close on route change
  useEffect(() => { closeMega(); }, [location, closeMega]);

  // Close on click outside
  useEffect(() => {
    if (!activeMega) return;
    const handleClick = (e) => {
      if (headerRef.current && !headerRef.current.contains(e.target)) {
        closeMega();
      }
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [activeMega, closeMega]);

  // Close on Escape
  useEffect(() => {
    if (!activeMega) return;
    const handleKey = (e) => { if (e.key === 'Escape') closeMega(); };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [activeMega, closeMega]);

  const handleNavClick = (key, e) => {
    if (key === 'women' || key === 'men') {
      e.preventDefault();
      setActiveMega((prev) => (prev === key ? null : key));
    }
  };

  const currentMenu = activeMega ? megaMenuData[activeMega] : null;

  return (
    <header className={styles.header} ref={headerRef}>
      <nav className={styles.nav}>
        {/* Desktop nav left */}
        <ul className={styles.navLeft}>
          {navLeft.map((item) => (
            <li key={item.key}>
              <a
                href="#!"
                className={`${styles.navLink} ${activeMega === item.key ? styles.navLinkActive : ''}`}
                onClick={(e) => handleNavClick(item.key, e)}
              >
                {item.label}
              </a>
            </li>
          ))}
        </ul>

        {/* Mobile hamburger */}
        <button
          className={styles.menuBtn}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Menu"
        >
          <svg width="18" height="12" viewBox="0 0 18 12" fill="none">
            <line y1="0.5" x2="18" y2="0.5" stroke="currentColor" />
            <line y1="5.5" x2="18" y2="5.5" stroke="currentColor" />
            <line y1="10.5" x2="18" y2="10.5" stroke="currentColor" />
          </svg>
        </button>

        <Link to="/" className={styles.logo}>
          <img src={logo} alt="RECTO" className={styles.logoImg} />
        </Link>

        {/* Desktop nav right */}
        <ul className={styles.navRight}>
          {navRight.map((item) => (
            <li key={item}>
              <a href="#!" className={styles.navLink}>{item}</a>
            </li>
          ))}
          <li>
            <Link to="/cart" className={styles.navLink}>
              BAG{cartCount > 0 && `(${cartCount})`}
            </Link>
          </li>
        </ul>

        {/* Mobile icons */}
        <div className={styles.mobileIcons}>
          <button className={styles.iconBtn} aria-label="Search">
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <circle cx="6.5" cy="6.5" r="5.5" stroke="currentColor" strokeWidth="1" />
              <line x1="10.5" y1="10.5" x2="15" y2="15" stroke="currentColor" strokeWidth="1" />
            </svg>
          </button>
          <button className={styles.iconBtn} aria-label="Cart">
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M3 4L4 14H12L13 4" stroke="currentColor" strokeWidth="1" />
              <path d="M5.5 4V3C5.5 1.5 6.5 0.5 8 0.5C9.5 0.5 10.5 1.5 10.5 3V4" stroke="currentColor" strokeWidth="1" />
            </svg>
          </button>
        </div>
      </nav>

      {/* Mega Menu */}
      <div className={`${styles.megaMenu} ${activeMega ? styles.megaOpen : ''}`}>
        {currentMenu && (
          <div className={styles.megaInner}>
            {Object.entries(currentMenu).map(([group, items]) => (
              <div key={group} className={styles.megaColumn}>
                <span className={styles.megaGroupTitle}>{group}</span>
                <ul className={styles.megaList}>
                  {items.map((item) => (
                    <li key={item.name}>
                      <Link to={item.link} className={styles.megaLink} onClick={closeMega}>
                        {item.name}
                      </Link>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Overlay */}
      {activeMega && <div className={styles.megaOverlay} onClick={closeMega} />}
    </header>
  );
}

export default Header;
